```typescript
type OpenFlow = {
  summary?: string;
  description?: string;
  value: FlowValue;
  schema?: any;
};

type FlowValue = {
  modules: FlowModule[];
  failure_module?: FlowModule;
  same_worker: boolean;
};

type FlowModule = {
  value: Identity | RawScript | PathScript | ForloopFlow | BranchOne | BranchAll;
  summary?: string;
  stop_after_if?: { expr: string; skip_if_stopped: boolean };
  sleep?: StaticTransform | JavascriptTransform;
  suspend?: { required_events?: integer, timeout: integer };
  retry?: Retry;
};

type BranchOne = {
  default: FlowModule[];
  branches: Array<{
    summary?: string;
    expr: string;
    modules: FlowModule[];
  }>;
};

type RawScript = {
  input_transforms: Record<string, StaticTransform | JavascriptTransform>;
  content: string;
  language: "deno" | "python3";
  path?: string;
};
```

